-- bridge/pause_control.lua\n-- Minimal deterministic pause control for DFHack 53.15‑r2 (updated)\nlocal Bridge = require('bridge')\n\nfunction Bridge.toggle_pause(pause)\n    -- Convert any truthy value to a boolean\n    pause = not not pause\n    -- Safely invoke the DFHack pause toggle; ignore errors to keep determinism\n    local ok, err = pcall(function()\n        if pause then\n            dfhack.game.togglePause(true)\n        else\n            dfhack.game.togglePause(false)\n        end\n    end)\n    -- Return a simple report exposing the outcome\n    return {\n        requested = pause,\n        success = ok,\n        error = ok and nil or err\n    }\nend\n\nreturn true
